function numDistinctRepeatedSubstrings(s) {
  let seen = new Set();
  for (let len = Math.floor(s.length / 2); len >= 1; len--) {
    for (let i = 0; i <= s.length - 2 * len; i++) {
      let substr = s.slice(i, i + len);
      if (s.indexOf(substr, i + len) !== -1)
        seen.add(substr);
    }
  }
  return seen.size;
}
