int numDistinctRepeatedSubstrings(String s) {
    HashSet<String> seen = new HashSet<>();
    for (int len = s.length() / 2; len >= 1; len--) {
        for (int i = 0; i <= s.length() - 2 * len; i++) {
            String substr = s.substring(i, i + len);
            if (s.indexOf(substr, i + len) != -1)
                seen.add(substr);
        }
    }
    return seen.size();
}
